const diffOutput = $('Diff Monday vs Calendar').all().map(x => x.json);
const updates = diffOutput.filter(d => d._branch === 'update');

return updates.map(u => ({
  json: {
    action: 'updated',
    title: u.title,
    eventId: u.eventId,
    start: u.startISO,
    changes: u.changes
  }
}));

const mondayResponse = $('Get Monday Items').first().json;
const items = mondayResponse?.data?.boards?.[0]?.items_page?.items || [];
const calendarEvents = $input.all().map(x => x.json).filter(e => e && e.status !== 'cancelled');

const DEFAULT_TIME_UTC = '06:00:00';
const BOARD_ID = '5093821351';

const desired = new Map();

for (const item of items) {
  const status = (item.column_values || []).find(c => c.id === 'project_status');
  const due = (item.column_values || []).find(c => c.id === 'date');

  if (status?.text === 'Done') continue;

  let dueDate = '';
  let dueTimeUTC = '';

  if (due?.value) {
    try {
      const parsed = typeof due.value === 'string' ? JSON.parse(due.value) : due.value;
      dueDate = parsed?.date || '';
      dueTimeUTC = parsed?.time || '';
    } catch (e) {}
  }

  if (!dueDate && due?.text) {
    dueDate = due.text.split(' ')[0] || '';
  }

  if (!dueDate) continue;

  const startTimeUTC = dueTimeUTC || DEFAULT_TIME_UTC;
  const startISO = `${dueDate}T${startTimeUTC}Z`;
  const endISO = new Date(new Date(startISO).getTime() + 30 * 60 * 1000).toISOString();

  const title = '📋 ' + item.name;
  const url = `https://alex-it.monday.com/boards/${BOARD_ID}/pulses/${item.id}`;

  desired.set(String(item.id), { title, startISO, endISO, url, itemId: item.id, itemName: item.name });
}

const current = new Map();

for (const event of calendarEvents) {
  if (!event.description) continue;
  const match = event.description.match(/\/pulses\/(\d+)/);
  if (!match) continue;
  const mondayId = match[1];
  if (!current.has(mondayId)) {
    current.set(mondayId, event);
  }
}

const toCreate = [];
const toUpdate = [];
const toDelete = [];

for (const [id, d] of desired) {
  if (!current.has(id)) {
    toCreate.push({ json: d });
  }
}

for (const [id, d] of desired) {
  const existing = current.get(id);
  if (!existing) continue;

  const existingStart = existing.start?.dateTime || existing.start?.date || '';
  const existingTitle = existing.summary || '';

  const existingMs = existingStart ? new Date(existingStart).getTime() : 0;
  const desiredMs = new Date(d.startISO).getTime();

  const titleChanged = existingTitle !== d.title;
  const timeChanged = existingMs !== desiredMs;

  if (titleChanged || timeChanged) {
    toUpdate.push({
      json: {
        ...d,
        eventId: existing.id,
        changes: {
          title: titleChanged ? { from: existingTitle, to: d.title } : null,
          time: timeChanged ? { from: existingStart, to: d.startISO } : null
        }
      }
    });
  }
}

for (const [id, event] of current) {
  if (!desired.has(id)) {
    const mondayItem = items.find(i => String(i.id) === id);
    let reason = 'Monday item deleted or archived';
    if (mondayItem) {
      const status = (mondayItem.column_values || []).find(c => c.id === 'project_status');
      if (status?.text === 'Done') {
        reason = 'Monday item marked Done';
      } else {
        reason = 'Monday item missing date';
      }
    }

    toDelete.push({
      json: {
        eventId: event.id,
        summary: event.summary,
        mondayId: id,
        reason
      }
    });
  }
}

return [
  { json: { _branch: 'meta', createCount: toCreate.length, updateCount: toUpdate.length, deleteCount: toDelete.length } },
  ...toCreate.map(x => ({ json: { _branch: 'create', ...x.json } })),
  ...toUpdate.map(x => ({ json: { _branch: 'update', ...x.json } })),
  ...toDelete.map(x => ({ json: { _branch: 'delete', ...x.json } }))
];

return $input.all().map(x => ({
  json: {
    action: 'created',
    title: x.json.summary,
    start: x.json.start?.dateTime || x.json.start?.date || '',
    eventId: x.json.id,
    link: x.json.htmlLink
  }
}));

const all = $input.all().map(x => x.json);

const created = all.filter(i => i.action === 'created');
const updated = all.filter(i => i.action === 'updated');
const deleted = all.filter(i => i.action === 'deleted');

return [{
  json: {
    timestamp: new Date().toISOString(),
    createdCount: created.length,
    updatedCount: updated.length,
    deletedCount: deleted.length,
    totalChanges: created.length + updated.length + deleted.length,
    created: created.map(c => ({
      title: c.title,
      start: c.start,
      eventId: c.eventId,
      link: c.link
    })),
    updated: updated.map(u => ({
      title: u.title,
      start: u.start,
      eventId: u.eventId,
      changes: u.changes
    })),
    deleted: deleted.map(d => ({
      title: d.title,
      eventId: d.eventId,
      mondayId: d.mondayId,
      reason: d.reason
    }))
  }
}];

const diffOutput = $('Diff Monday vs Calendar').all().map(x => x.json);
const deletes = diffOutput.filter(d => d._branch === 'delete');

return deletes.map(d => ({
  json: {
    action: 'deleted',
    title: d.summary,
    eventId: d.eventId,
    mondayId: d.mondayId,
    reason: d.reason
  }
}));

